import React from 'react';
import PropTypes from 'prop-types';
import { makeStyles } from '@material-ui/core/styles';
import FormControl from '@material-ui/core/FormControl';
import InputLabel from '@material-ui/core/InputLabel';
import Select from '@material-ui/core/Select';
import MenuItem from '@material-ui/core/MenuItem';

const useStyles = makeStyles((theme) => ({
  formControl: {
    margin: theme.spacing(1),
    minWidth: 120,
  },
}));

function CategorySelect({ selectedCategory, handleSelectChange, menuData, handleSubCategoryChange, selectedSubCategoryValues, existingCategories }) {
  const classes = useStyles();

  return (
    <FormControl className={classes.formControl}>
      <InputLabel htmlFor="category-select">Category</InputLabel>
      <Select
        value={selectedCategory}
        onChange={handleSelectChange}
        inputProps={{
          name: 'category',
          id: 'category-select',
        }}
      >
        {menuData.categories.map((category, index) => (
          <MenuItem key={index} value={category.main}>
            {category.main}
          </MenuItem>
        ))}
      </Select>
      <InputLabel htmlFor="sub-category-select">Subcategory</InputLabel>
      <Select
        multiple
        value={selectedSubCategoryValues}
        onChange={handleSubCategoryChange}
        inputProps={{
          name: 'subCategory',
          id: 'sub-category-select',
        }}
      >
        {menuData.subCategories[selectedCategory] &&
          menuData.subCategories[selectedCategory].map((subCategory, index) => (
            <MenuItem key={index} value={subCategory}>
              {subCategory}
            </MenuItem>
          ))}
      </Select>
    </FormControl>
  );
}

CategorySelect.propTypes = {
  selectedCategory: PropTypes.string.isRequired,
  handleSelectChange: PropTypes.func.isRequired,
  menuData: PropTypes.object.isRequired,
  handleSubCategoryChange: PropTypes.func.isRequired,
  selectedSubCategoryValues: PropTypes.array.isRequired,
  existingCategories: PropTypes.array.isRequired,
};

export default CategorySelect;
